<template><div><div class="center-head"><div><h3>Environment Center</h3><p>为每个交付阶段维护独立的 Kubernetes 运行配置</p></div><div><el-button @click="openCompare" :disabled="environments.length<2">环境对比</el-button><el-button type="primary" @click="openCreate">＋ 新建环境</el-button></div></div><el-skeleton :loading="loading" animated :rows="6"><div class="env-grid"><article v-for="env in environments" :key="env.id" class="surface env-card"><header><span class="env-icon" :class="env.environment_name">{{env.environment_name.slice(0,2).toUpperCase()}}</span><div><h4>{{env.display_name||env.environment_name}}</h4><small>{{env.cluster_name}} / {{env.namespace}}</small></div><StatusBadge :status="env.status"/></header><dl><div><dt>Replicas</dt><dd>{{env.replicas}}</dd></div><div><dt>Strategy</dt><dd>{{env.deploy_strategy}}</dd></div><div><dt>CPU</dt><dd>{{env.cpu_request}} / {{env.cpu_limit}}</dd></div><div><dt>Memory</dt><dd>{{env.memory_request}} / {{env.memory_limit}}</dd></div></dl><div class="domain"><span>Domain</span><code>{{env.ingress_domain||'Not configured'}}</code></div><footer><span v-if="env.approval_required">◆ Approval required</span><span v-else>Direct delivery</span><el-dropdown trigger="click"><el-button link>Manage ···</el-button><template #dropdown><el-dropdown-menu><el-dropdown-item @click="edit(env)">编辑配置</el-dropdown-item><el-dropdown-item @click="clone(env)">克隆环境</el-dropdown-item><el-dropdown-item @click="exportConfig(env)">导出配置</el-dropdown-item><el-dropdown-item divided :disabled="env.environment_name==='prod'" @click="remove(env)">删除环境</el-dropdown-item></el-dropdown-menu></template></el-dropdown></footer></article></div></el-skeleton><el-dialog v-model="dialog" :title="editing?.id?'编辑环境':'新建环境'" width="620px"><el-form label-position="top"><div class="form-grid"><el-form-item label="环境标识"><el-input v-model="form.environment_name" :disabled="!!editing?.id" placeholder="qa"/></el-form-item><el-form-item label="显示名称"><el-input v-model="form.display_name" placeholder="QA"/></el-form-item><el-form-item label="Kubernetes Namespace"><el-input v-model="form.namespace"/></el-form-item><el-form-item label="副本数"><el-input-number v-model="form.replicas" :min="1" :max="100"/></el-form-item><el-form-item label="CPU Request / Limit"><div class="inline"><el-input v-model="form.cpu_request"/><el-input v-model="form.cpu_limit"/></div></el-form-item><el-form-item label="Memory Request / Limit"><div class="inline"><el-input v-model="form.memory_request"/><el-input v-model="form.memory_limit"/></div></el-form-item><el-form-item label="Ingress Domain"><el-input v-model="form.ingress_domain"/></el-form-item><el-form-item label="发布策略"><el-select v-model="form.deploy_strategy"><el-option v-for="s in strategies" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item label="生产审批"><el-switch v-model="form.approval_required"/></el-form-item></div></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="saving" @click="save">保存配置</el-button></template></el-dialog><el-dialog v-model="compareDialog" title="环境配置对比" width="760px"><div class="compare-picker"><el-select v-model="compareLeft"><el-option v-for="e in environments" :key="e.id" :label="e.display_name||e.environment_name" :value="e.id"/></el-select><span>vs</span><el-select v-model="compareRight"><el-option v-for="e in environments" :key="e.id" :label="e.display_name||e.environment_name" :value="e.id"/></el-select><el-button @click="compare">对比</el-button></div><el-table :data="differences"><el-table-column prop="field" label="配置项"/><el-table-column label="环境 A"><template #default="{row}"><code>{{display(row.left)}}</code></template></el-table-column><el-table-column label="环境 B"><template #default="{row}"><code>{{display(row.right)}}</code></template></el-table-column><el-table-column label="差异" width="80"><template #default="{row}"><span :class="{changed:row.changed}">{{row.changed?'Changed':'Same'}}</span></template></el-table-column></el-table></el-dialog></div></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{applicationApi}from'../../api/application';import type{ApplicationEnvironment}from'../../types';import StatusBadge from'../common/StatusBadge.vue';const p=defineProps<{applicationId:number}>(),environments=ref<ApplicationEnvironment[]>([]),loading=ref(false),saving=ref(false),dialog=ref(false),editing=ref<ApplicationEnvironment>(),compareDialog=ref(false),compareLeft=ref(0),compareRight=ref(0),differences=ref<any[]>([]),strategies=['RollingUpdate','Recreate'];const defaults={environment_name:'',display_name:'',namespace:'',replicas:1,cpu_request:'100m',cpu_limit:'500m',memory_request:'128Mi',memory_limit:'512Mi',ingress_domain:'',deploy_strategy:'RollingUpdate',approval_required:false};const form=reactive({...defaults});async function load(){loading.value=true;try{environments.value=await applicationApi.environments(p.applicationId)}finally{loading.value=false}}function openCreate(){editing.value=undefined;Object.assign(form,defaults);dialog.value=true}function edit(env:ApplicationEnvironment){editing.value=env;Object.assign(form,env);dialog.value=true}async function save(){saving.value=true;try{if(editing.value)await applicationApi.updateEnvironment(p.applicationId,editing.value.id,form);else await applicationApi.createEnvironment(p.applicationId,form);ElMessage.success('环境配置已保存');dialog.value=false;await load()}finally{saving.value=false}}async function clone(env:ApplicationEnvironment){const{value}=await ElMessageBox.prompt('输入新环境标识，例如 qa','克隆环境',{inputPattern:/^[a-z][a-z0-9-]*$/,inputErrorMessage:'仅支持小写字母、数字和连字符'});await applicationApi.cloneEnvironment(p.applicationId,env.id,value);ElMessage.success('环境已克隆');load()}async function remove(env:ApplicationEnvironment){await ElMessageBox.confirm(`确认删除 ${env.display_name||env.environment_name}？该操作不会删除 Kubernetes 工作负载。`,'危险操作',{type:'warning'});await applicationApi.deleteEnvironment(p.applicationId,env.id);ElMessage.success('环境已删除');load()}function exportConfig(env:ApplicationEnvironment){const blob=new Blob([JSON.stringify(env,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${env.environment_name}-environment.json`;a.click();URL.revokeObjectURL(a.href)}function openCompare(){compareLeft.value=environments.value[0]?.id||0;compareRight.value=environments.value[1]?.id||0;compareDialog.value=true;compare()}async function compare(){if(compareLeft.value&&compareRight.value)differences.value=await applicationApi.compareEnvironments(p.applicationId,compareLeft.value,compareRight.value)}const display=(v:unknown)=>typeof v==='object'?JSON.stringify(v):String(v??'—');onMounted(load)
</script>
<style scoped>.center-head{display:flex;justify-content:space-between;align-items:end;margin-bottom:14px}.center-head h3{font-size:14px;margin:0 0 5px}.center-head p{font-size:13px;color:var(--muted);margin:0}.env-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:13px}.env-card{padding:0;overflow:hidden;box-shadow:none}.env-card header{display:flex;align-items:center;gap:10px;padding:15px 16px;border-bottom:1px solid var(--border-soft)}.env-icon{width:32px;height:32px;display:grid;place-items:center;border-radius:8px;background:rgba(92,156,242,.1);color:#72aff5;font-size:12px;font-weight:700}.env-icon.prod{background:rgba(231,99,111,.1);color:#e87982}.env-icon.staging{background:rgba(230,169,80,.1);color:#e6b568}.env-card header div{flex:1}.env-card h4,.env-card small{display:block}.env-card h4{font-size:13px;margin:0 0 4px}.env-card small{font-size:12px;color:var(--muted)}.env-card dl{display:grid;grid-template-columns:1fr 1fr;margin:0;padding:8px 16px}.env-card dl div{padding:9px 0}.env-card dt{font-size:13px;color:var(--subtle)}.env-card dd{font-size:13px;margin:4px 0 0}.domain{padding:0 16px 14px}.domain span,.domain code{display:block}.domain span{font-size:13px;color:var(--subtle);margin-bottom:5px}.domain code{padding:7px;background:#0b0e13;border-radius:5px;color:#818b9d;font-size:12px}.env-card footer{height:42px;padding:0 16px;border-top:1px solid var(--border-soft);display:flex;align-items:center;justify-content:space-between;color:#7066ce;font-size:12px}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:0 14px}.inline{display:flex;gap:7px}.compare-picker{display:flex;align-items:center;gap:10px;margin-bottom:15px}.compare-picker .el-select{flex:1}.changed{color:var(--warning)}code{font-size:12px;color:var(--text-2)}@media(max-width:1000px){.env-grid{grid-template-columns:1fr}}</style>
